import hashlib
import numpy as np
from typing import Tuple
import secrets

class HashAnalyzer:
    def __init__(self, hash_func=hashlib.sha256):
        self.hash_func = hash_func

    def hash(self, data: bytes) -> bytes:
        return self.hash_func(data).digest()

    def measure_avalanche_effect(self, message: bytes,
                                  num_bit_flips: int = 100) -> float:
        original_hash = self.hash(message)
        total_bits_changed = 0
        total_bits = len(original_hash) * 8

        msg_array = bytearray(message)

        for _ in range(num_bit_flips):
            # Flip a random bit
            byte_idx = np.random.randint(0, len(msg_array))
            bit_idx = np.random.randint(0, 8)

            modified = bytearray(msg_array)
            modified[byte_idx] ^= (1 << bit_idx)

            new_hash = self.hash(bytes(modified))

            # Count differing bits
            diff = sum(bin(a ^ b).count('1') for a, b in zip(original_hash, new_hash))
            total_bits_changed += diff

        return (total_bits_changed / num_bit_flips) / total_bits * 100

    def estimate_preimage_difficulty(self, target_bits: int = 16) -> Tuple[int, bytes]:
        attempts = 0

        while True:
            attempts += 1
            message = secrets.token_bytes(32)
            h = self.hash(message)

            # Check if first target_bits are zero
            leading_zeros = 0
            for byte in h:
                if byte == 0:
                    leading_zeros += 8
                else:
                    leading_zeros += 8 - byte.bit_length()
                    break

            if leading_zeros >= target_bits:
                return attempts, message

            if attempts > 2 ** (target_bits + 2):
                return attempts, None

    def demonstrate_collision_birthday(self, hash_bits: int = 24) -> dict:
        seen = {}
        attempts = 0

        while True:
            attempts += 1
            message = secrets.token_bytes(32)
            h = self.hash(message)[:hash_bits // 8]

            if h in seen:
                return {
                    'attempts': attempts,
                    'expected_attempts': int(np.sqrt(2 ** hash_bits)),
                    'message1': seen[h],
                    'message2': message,
                    'truncated_hash': h.hex()
                }

            seen[h] = message

            if attempts > 2 ** (hash_bits // 2 + 4):
                return {'attempts': attempts, 'found': False}

import hashlib
import secrets
from typing import Tuple, List

class LamportSignature:
    def __init__(self, security_bits: int = 256):
        self.n = security_bits
        self.hash_bytes = security_bits // 8

    def _hash(self, data: bytes) -> bytes:
        return hashlib.sha256(data).digest()[:self.hash_bytes]

    def keygen(self) -> Tuple[List[Tuple[bytes, bytes]],
                               List[Tuple[bytes, bytes]]]:
        sk = []
        pk = []

        for _ in range(self.n):
            sk_0 = secrets.token_bytes(self.hash_bytes)
            sk_1 = secrets.token_bytes(self.hash_bytes)
            pk_0 = self._hash(sk_0)
            pk_1 = self._hash(sk_1)
            sk.append((sk_0, sk_1))
            pk.append((pk_0, pk_1))

        return sk, pk

    def sign(self, sk: List[Tuple[bytes, bytes]],
             message: bytes) -> List[bytes]:
        msg_hash = self._hash(message)
        signature = []

        for i, byte in enumerate(msg_hash):
            for j in range(8):
                bit_idx = i * 8 + j
                if bit_idx >= self.n:
                    break
                bit = (byte >> (7 - j)) & 1
                signature.append(sk[bit_idx][bit])

        return signature

    def verify(self, pk: List[Tuple[bytes, bytes]],
               message: bytes, signature: List[bytes]) -> bool:
        msg_hash = self._hash(message)

        for i, byte in enumerate(msg_hash):
            for j in range(8):
                bit_idx = i * 8 + j
                if bit_idx >= len(signature):
                    break
                bit = (byte >> (7 - j)) & 1

                if self._hash(signature[bit_idx]) != pk[bit_idx][bit]:
                    return False

        return True

    def get_sizes(self) -> dict:
        return {
            'secret_key_bytes': 2 * self.n * self.hash_bytes,
            'public_key_bytes': 2 * self.n * self.hash_bytes,
            'signature_bytes': self.n * self.hash_bytes
        }
